                'meta_title' => 'Wi-Fi Lemot Padahal Sinyal Penuh? Ini Penyebabnya',
                'meta_description' => 'Kenali penyebab Wi-Fi lemot meski sinyal penuh: interferensi, channel padat, router overload, DNS lambat, dan solusi praktisnya.',
                'published_at' => now()->setTime(8, 10),
